), updated as (
  update yy_booking_slot_inventory target
     set capacity = source.capacity,
         paid_count = source.paid_count,
         conflict_count = source.conflict_count,
         status = source.status,
         update_by = source.update_by,
         update_time = now(),
         del_flag = '0',
         remark = source.remark
    from source
   where target.tenant_id = source.tenant_id
     and target.store_id = source.store_id
     and coalesce(target.service_group_id, 0) = coalesce(source.service_group_id, 0)
     and coalesce(target.external_sku_id, '') = coalesce(source.external_sku_id, '')
     and target.biz_date = source.biz_date
     and target.start_time = source.start_time
     and target.end_time = source.end_time
     and target.del_flag = '0'
  returning target.id
)
insert into yy_booking_slot_inventory
(id, tenant_id, store_id, service_group_id, external_sku_id, biz_date, start_time, end_time, capacity, paid_count, conflict_count, status, version, create_dept, create_by, create_time, update_by, update_time, del_flag, remark)
select source.*
  from source
 where not exists (
   select 1 from yy_booking_slot_inventory target
    where target.tenant_id = source.tenant_id
      and target.store_id = source.store_id
      and coalesce(target.service_group_id, 0) = coalesce(source.service_group_id, 0)
      and coalesce(target.external_sku_id, '') = coalesce(source.external_sku_id, '')
      and target.biz_date = source.biz_date
      and target.start_time = source.start_time
      and target.end_time = source.end_time
      and target.del_flag = '0'
 );

